    'bsp-qradar-audit-logs-rest': {
        title: 'Audit Log Sync to IBM QRadar (REST API) – Browser Security Plus',
        content: `
            <h3>Description</h3>
            <p>This feature sends <strong>Action Log Viewer (audit log)</strong> data from <strong>Browser Security Plus</strong> to <strong>IBM QRadar</strong> via <strong>REST API</strong>. QRadar can then apply its offense detection, correlation rules, and reporting to track administrative events from Browser Security Plus.</p>

            <h3>How This Works</h3>
            <ol><li>Enable the QRadar integration in Browser Security Plus under Admin → Integrations → QRadar.</li><li>Configure the QRadar REST API endpoint URL and authentication token.</li><li>Browser Security Plus sends audit log entries to QRadar's REST API at configured intervals.</li><li>QRadar ingests and correlates the data alongside other log sources.</li></ol>

            <h3>Prerequisites</h3>
            <ul>
                <li>IBM QRadar instance with REST API access enabled and a valid authentication token.</li>
                <li>Browser Security Plus server must have network access to QRadar on the configured port.</li>
                <li>The integration must be enabled in Browser Security Plus.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>REST API method may have rate limits depending on QRadar configuration.</li>
                <li>Only audit log data is forwarded via this feature.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Browser Security Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/qradarintegration.log</code></li>
                <li>Verify REST API endpoint and token in integration settings.</li>
            </ul>
            
        `,
        links: []
    },
