    'rap-op-ap-default-sync-1': {
        title: 'Default Data Sync to Analytics Plus – Remote Access Plus',
        content: `
            <h3>Description</h3>
            <p>This feature enables <strong>default data synchronization</strong> from <strong>Remote Access Plus</strong> to <strong>Analytics Plus</strong>. The following data categories are synced automatically once the integration is enabled:</p>
            <p><strong>Data synced:</strong> Custom groups, Technicians, User accounts, Patch scan summary, Software usage, USB audit, Applications and associated patches</p>

            <h3>How This Works</h3>
            <ol>
                <li>Enable the Analytics Plus integration in Remote Access Plus under Admin → Integrations → Analytics Plus.</li>
                <li>Provide the Analytics Plus server URL and API credentials.</li>
                <li>Remote Access Plus automatically pushes the default data categories to Analytics Plus on a scheduled basis.</li>
                <li>In Analytics Plus, the data is available for creating custom reports, dashboards, and analytics.</li>
            </ol>

            <h3>Prerequisites</h3>
            <ul>
                <li>Analytics Plus must be installed and accessible from the Remote Access Plus server.</li>
                <li>API credentials must be configured.</li>
                <li>The default sync does not require additional feature selection — it is enabled automatically with the integration.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>Default sync includes a fixed set of data categories. For additional data, enable Optional Data Synchronization.</li>
                <li>Sync frequency depends on the configured schedule — large datasets may take longer.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Remote Access Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/analyticsintegration.log</code></li>
                <li>Verify Analytics Plus URL and credentials in Remote Access Plus → Admin → Integrations.</li>
            </ul>
            
        `,
        links: []
    },
